class RetryPolicy:
    def __init__(self, max_attempts: int):
        self.max_attempts = max_attempts

    def should_retry(self, attempt_count: int, status_code: int) -> bool:
        if attempt_count >= self.max_attempts:
            return False
        return status_code >= 500

