class RetryRules:
    def __init__(self, attempt_limit: int):
        self.attempt_limit = attempt_limit

    def can_try_again(self, attempts_made: int, response_code: int) -> bool:
        if attempts_made >= self.attempt_limit:
            return False
        return response_code >= 500

